const raw = ($input.first().json.content?.parts?.[0]?.text || "").toString();

// Remove triple-backtick blocks and whitespace
let cleaned = raw.replace(/```(?:json)?/g, '').trim();

// Parse JSON
let result = {};
try {
  const obj = JSON.parse(cleaned);
  if (obj && typeof obj === 'object') {
    result = obj; // directly assign key-value pairs
  }
} catch (e) {
  // JSON parsing failed, fallback
  result = { error: "Invalid JSON" };
}

// return as array of JSON (like in n8n)
return [{ json: result }];

// Get all input items
const items = $input.all();

// Filter out empty items (no keys or null data)
const nonEmptyItems = items.filter(item => {
  const data = item.json;
  return data && Object.keys(data).length > 0;
});

let resultData = { result: false };

// If there’s any non-empty item, take the first one’s data
if (nonEmptyItems.length > 0) {
  resultData = {
    ...nonEmptyItems[0].json, // keep the actual data
    result: true
  };
}

// Return a single output object
return [{ json: resultData }];

