const raw = ($input.first().json.message?.content || "").toString();

// remove triple-backtick blocks and leading/trailing whitespace
let output = raw.replace(/```(?:json)?/g, '').trim();

// if the assistant returned a quoted string like "report_request", remove surrounding quotes
if (/^["'].*["']$/.test(output)) {
  output = output.slice(1, -1).trim();
}

let categories = [];

try {
  // Try JSON first
  const maybeObj = JSON.parse(output);
  if (Array.isArray(maybeObj)) {
    categories = maybeObj.map(v => v.toString().trim());
  } else if (typeof maybeObj === "object") {
    if (Array.isArray(maybeObj.categories)) categories = maybeObj.categories;
    else if (maybeObj.category) categories = [maybeObj.category];
    else categories = Object.values(maybeObj).map(v => v.toString().trim());
  } else if (typeof maybeObj === "string") {
    categories = [maybeObj.trim()];
  }
} catch (e) {
  // Fallback: split by newlines or commas
  categories = output
    .split(/[\n,]+/)
    .map(s => s.replace(/["']/g, '').trim())
    .filter(Boolean);
}

// n8n requires array of objects - return one object per category
return categories.map(cat => ({ json: { category: cat } }));

