// Get Gmail thread JSON
const thread = $('Get Complete Thread').first().json;
const messages = thread.messages || [];

let combined = '';
let latestSnippet =
  thread.snippet ||
  ($('Gmail Trigger2').first()?.json?.snippet || '');

// 🔹 Single domain to detect
const batraDomain = '@thebatraanumerology.com';

let hasBatraInThread = false;
let isLastFromBatra = false;

// Helper: extract header from different structures
function getHeader(msg, headerName) {
  if (!msg) return '';

  if (msg[headerName]) return msg[headerName];
  if (msg[headerName.toLowerCase()]) return msg[headerName.toLowerCase()];

  if (Array.isArray(msg.headers)) {
    const h = msg.headers.find(
      h => (h.name || '').toLowerCase() === headerName.toLowerCase()
    );
    if (h?.value) return h.value;
  }

  if (msg.payload?.headers) {
    const h = msg.payload.headers.find(
      h => (h.name || '').toLowerCase() === headerName.toLowerCase()
    );
    if (h?.value) return h.value;
  }

  return '';
}

// Helper: extract plain email (handle "Name <email>" format)
function normalizeEmail(raw) {
  if (!raw) return '';
  const match = raw.match(/<([^>]+)>/);
  return (match ? match[1] : raw).trim().toLowerCase();
}

// Loop messages
for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];

  const fromRaw = getHeader(msg, 'From');
  const toRaw = getHeader(msg, 'To');
  const subjectRaw = getHeader(msg, 'Subject');
  const snippet = msg.snippet || '(No message text)';

  const fromNorm = normalizeEmail(fromRaw);

  // ✅ Detect if sender email contains the domain
  if (fromNorm.includes(batraDomain.toLowerCase())) {
    hasBatraInThread = true;

    if (i === messages.length - 1) {
      isLastFromBatra = true;
    }
  }

  combined += `\n\n====================\n`;
  combined += `Message ${i + 1}\n`;
  combined += `From: ${fromRaw || '(Unknown sender)'}\n`;
  combined += `To: ${toRaw || '(Unknown recipient)'}\n`;
  combined += `Subject: ${subjectRaw || '(No subject)'}\n`;
  combined += `--------------------\n`;
  combined += snippet;
}

// Output
return [
  {
    latest_message: latestSnippet,
    conversation_full: combined,
    has_batra_in_thread: hasBatraInThread,
    is_last_from_batra: isLastFromBatra,
  },
];

